UPDATE ChallengeParticipation
SET prize = COALESCE(prize,0) + #{payout},
    updated_at = NOW()
WHERE challenge_id = #{challengeId}
  AND user_id = #{userId}

UPDATE ChallengeParticipation
SET prize = COALESCE(prize,0) - #{amount},
    updated_at = NOW()
WHERE challenge_id = #{challengeId}
  AND user_id = #{userId}
